use std::time::Instant;

// A timer that prints elapsed time when dropped
struct Timer {
    label: String,
    start: Instant,
}

impl Timer {
    fn new(label: &str) -> Self {
        println!("[{}] Starting...", label);
        Timer {
            label: label.to_string(),
            start: Instant::now(),
        }
    }
}

impl Drop for Timer {
    fn drop(&mut self) {
        let elapsed = self.start.elapsed();
        println!("[{}] Finished in {:?}", self.label, elapsed);
    }
}

// A temporary directory that cleans itself up
struct TempDir {
    path: std::path::PathBuf,
}

impl TempDir {
    fn new(prefix: &str) -> std::io::Result<Self> {
        let path = std::env::temp_dir().join(format!("{}-{}", prefix, std::process::id()));
        std::fs::create_dir_all(&path)?;
        Ok(TempDir { path })
    }

    fn path(&self) -> &std::path::Path {
        &self.path
    }
}

impl Drop for TempDir {
    fn drop(&mut self) {
        let _ = std::fs::remove_dir_all(&self.path);
        println!("Cleaned up temp dir: {:?}", self.path);
    }
}

fn main() {
    {
        let _timer = Timer::new("computation");
        // Simulate work
        let sum: u64 = (0..1_000_000).sum();
        println!("Sum: {}", sum);
    } // Timer::drop() runs here, prints elapsed time

    {
        let tmp = TempDir::new("myapp").unwrap();
        println!("Using temp dir: {:?}", tmp.path());
        // Even if we return early or panic, the directory is cleaned up
    } // TempDir::drop() removes the directory
}
